const MAX_MESSAGES = 4;
const texto = $input.first().json.output.respuesta_mensaje || '';

// Paso 1: parto en oraciones por puntuación o saltos de línea
const oraciones = texto
  .replace(/([.!?])\s+/g, '$1|||')
  .replace(/\n+/g, '|||')
  .split('|||')
  .map(s => s.trim())
  .filter(s => s.length > 0);

// Paso 2: si son <= MAX_MESSAGES, dejo una por mensaje
// Si son más, distribuyo en exactamente MAX_MESSAGES grupos lo más parejos posibles
let mensajes;
if (oraciones.length <= MAX_MESSAGES) {
  mensajes = oraciones;
} else {
  mensajes = [];
  const base = Math.floor(oraciones.length / MAX_MESSAGES);
  const resto = oraciones.length % MAX_MESSAGES;
  let idx = 0;
  for (let i = 0; i < MAX_MESSAGES; i++) {
    const tamano = base + (i < resto ? 1 : 0); // los primeros 'resto' grupos llevan 1 oración extra
    mensajes.push(oraciones.slice(idx, idx + tamano).join(' '));
    idx += tamano;
  }
}

return [{ json: { output: { mensajes }, agente_output: $input.first().json.output } }];

// Limpia el mensaje para Telegram en modo HTML.
// 1) Escapa & < > (evita el error 400 por tags rotos)
// 2) Convierte **negrita** de Markdown a <b>negrita</b> de HTML

let txt = String($json.mensaje ?? '');

// 1) Escapar caracteres especiales de HTML
txt = txt
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

// 2) **texto** -> <b>texto</b>  (pares; si queda uno suelto, lo deja literal)
txt = txt.replace(/\*\*(.+?)\*\*/g, '<b>$1</b>');

return [{
  json: {
    ...$json,
    mensaje: txt,
  },
}];

